import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { connect } from "./redux/blockchain/blockchainActions";
import { fetchData } from "./redux/data/dataActions";
import * as s from "./styles/globalStyles";
import styled from "styled-components";
import logo from './images/logo.png';
import example1 from './images/gif1.gif';
import { motion } from "framer-motion";
import background from './images/bg.webp';

const truncate = (input, len) =>
  input.length > len ? `${input.substring(0, len)}...` : input;

export const StyledButton = styled.button`
  padding: 10px;
  border-radius: 10px;
  border: 1px solid #fff;
  padding: 10px;
  background-color: rgba(250, 250, 250, 0);
  font-weight: bold;
  font-size: 18px;
  color: #fff;
  width: 150px;
  height: 50px;
  
  :active {
    box-shadow: none;
    -webkit-box-shadow: none;
    -moz-box-shadow: none;
  }

  &:hover{
    transform: scale(1.1);
    transition: all 0.2s ease-in-out;
    cursor: pointer;
    color: #5a405e;
    background-color: rgba(250, 250, 250, 1);
  }
`;

export const StyledButton2 = styled.button`
  padding: 10px;
  border-radius: 10px;
  border: 1px solid #fff;
  padding: 10px;
  background-color: rgba(250, 250, 250, 0);
  font-weight: bold;
  font-size: 18px;
  color: #fff;
  width: 250px;
  height: 50px;

  @media (max-width: 1200px) {
    font-size: 14px;
  }

  @media (max-width: 767px) {
    font-size: 12px;
  }

  &:hover{
    transition: all 0.2s ease-in-out;
    cursor: pointer;
    color: #5a405e;
    background-color: rgba(250, 250, 250, 1);
  }
`;

export const StyledRoundButton = styled.button`
  padding: 10px;
  border-radius: 10px;
  border: none;
  background-color: var(--primary);
  padding: 10px;
  font-weight: bold;
  font-size: 48px;
  color: #301934;
  width: 35px;
  height: 35px;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0px 4px 0px -2px rgba(250, 250, 250, 0.3);
  -webkit-box-shadow: 0px 4px 0px -2px rgba(250, 250, 250, 0.3);
  -moz-box-shadow: 0px 4px 0px -2px rgba(250, 250, 250, 0.3);

  :active {
    box-shadow: none;
    -webkit-box-shadow: none;
    -moz-box-shadow: none;
  }

  &:hover{
    transition: all 0.2s ease-in-out;
    cursor: pointer;
    transform: scale(1.1);
    color: #5a405e;
  }
`;

export const ResponsiveWrapper = styled.div`
  display: flex;
  flex: 1;
  flex-direction: row;
  align-items: center;
  width: 100%;

  @media (max-width: 1200px) {
    flex-direction: column;
    width: 800px;
  }

  @media (max-width: 767px) {
    flex-direction: column;
    width: 400px;
  }
`;

export const StyledLogo = styled(motion.img)`
  width: 600px;
  transition: width 0.5s;
  transition: height 0.5s;
  position: relative;
  z-index: 1;

  @media (max-width: 1200px) {
    width: 400px;
  }

  @media (max-width: 767px) {
    width: 200px;
  }
`;

export const StyledImg = styled(motion.img)`
  box-shadow: 0px 5px 11px 2px rgba(0, 0, 0, 0.7);
  border: 4px solid #fff;
  background-color: var(--accent);
  border-radius: 20px;
  width: 200px;
  box-shadow: 0px 5px 11px 2px rgba(255,255,255,0.8);

  @media (min-width: 900px) {
    width: 250px;
  }
  @media (min-width: 1000px) {
    width: 300px;
  }
  transition: width 0.5s;
`;

export const StyledLink = styled.a`
  color: #fff;
  text-decoration: none;

  &:hover{
    cursor: pointer;
    transition: all 0.2s ease-in-out;
  }
`;

function App() {
  const preSalePrice = 0.095;
  const publicSalePrice = 0.15;
  const dispatch = useDispatch();
  const blockchain = useSelector((state) => state.blockchain);
  const data = useSelector((state) => state.data);
  const [claimingNft, setClaimingNft] = useState(false);
  const [feedback, setFeedback] = useState(`1 WALLET = 1 NFT, WHITELISTED ONLY`);
  const [mintAmount, setMintAmount] = useState(1);
  const [CONFIG, SET_CONFIG] = useState({
    CONTRACT_ADDRESS: "",
    SCAN_LINK: "",
    NETWORK: {
      NAME: "",
      SYMBOL: "",
      ID: 0,
    },
    NFT_NAME: "",
    SYMBOL: "",
    MAX_SUPPLY: 1,
    WEI_COST: 0,
    DISPLAY_COST: 0,
    GAS_LIMIT: 0,
    MARKETPLACE: "",
    MARKETPLACE_LINK: "",
    SHOW_BACKGROUND: false,
  });

  const fadeLeft = {
    hidden: { opacity: 0, x: -100 },
    visible: { opacity: 1, x: 0 },
  }

  const fadeRight = {
    hidden: { opacity: 0, x: 100 },
    visible: { opacity: 1, x: 0 },
  }

  const fadeDown = {
    hidden: { opacity: 0, y: -100 },
    visible: { opacity: 1, y: 0 },
  }

  const fadeIn = {
    hidden: { opacity: 0},
    visible: { opacity: 1},
  }

  const mint = () => {
    setFeedback(`Minting your ${CONFIG.NFT_NAME}...`);
    setClaimingNft(true);

    //Send message to smartcontact
    blockchain.smartContract.methods
    .claimFreeNft2(blockchain.account)
    .estimateGas({ from: blockchain.account, to: CONFIG.CONTRACT_ADDRESS})
    .then(gasEstimate => {
      return blockchain.smartContract.methods
      .claimFreeNft2(blockchain.account)
      .send({
        gas: gasEstimate + 100000,
        to: CONFIG.CONTRACT_ADDRESS,
        from: blockchain.account,
      })
      .once("error", (err) => {
        console.log(err);
        setFeedback("Sorry, something went wrong please try again later.");
        setClaimingNft(false);
      })
      .then((receipt) => {
        console.log(receipt);
        setFeedback(
          `WOW, the ${CONFIG.NFT_NAME} is yours! go visit Opensea.io to view it.`
        );
        setClaimingNft(false);
        dispatch(fetchData(blockchain.account));
      });
    })
    .catch((error) => {
      console.log(error);
      setClaimingNft(false);
      setFeedback("You are not whitelisted or already claimed");
    });  
  };

  const getData = () => {
    if (blockchain.account !== "" && blockchain.smartContract !== null) {
      dispatch(fetchData(blockchain.account));
    }
  };

  const getConfig = async () => {
    const configResponse = await fetch("/config/config.json", {
      headers: {
        "Content-Type": "application/json",
        Accept: "application/json",
      },
    });
    const config = await configResponse.json();
    SET_CONFIG(config);
  };

  useEffect(() => {
    getConfig();
  },);

  useEffect(() => {
    getData();
  }, [blockchain.account]);

  return (
    <s.Screen>
      <s.Container
        flex={1}
        ai={"center"}
        style={{ backgroundColor: "var(--primary)", backgroundBlendMode: 'darken'}}
        image={background}
      >
        <s.SpacerMedium />
        <StyledLogo initial='hidden' animate='visible' variants={fadeDown} transition={{duration: 1}} alt={"logo"} src={logo} />
        <s.SpacerSmall />
        <ResponsiveWrapper flex={1} style={{ padding: 24 }} test>
          <s.Container flex={1} jc={"center"} ai={"center"}>
            <StyledImg initial='hidden' animate='visible' variants={fadeLeft} transition={{duration: 1}} drag={true} dragConstraints={{left: 0, right: 0, top: 0, bottom: 0}}
             alt={"example"} src={example1} />
          </s.Container>
          <s.SpacerLarge />
          <s.Container
          initial='hidden' animate='visible' variants={fadeIn} transition={{duration: 1}}
            flex={2}
            jc={"center"}
            ai={"center"}
            style={{
              background: "rgba(51,104,44,0.8)",
              padding: 24,
              borderRadius: 24,
              maxWidth: "600px",
              border: "4px solid #fff ",
              boxShadow: "0px 5px 11px 2px rgba(0,0,0,0.6)",
            }}
          >
            {blockchain.account === "" ||
                blockchain.smartContract === null ? (
                  <>
                  <s.TextTitle2>
                    Connect to see more
                  </s.TextTitle2>
                  <s.TextDescription
                  style={{
                  textAlign: "center",
                  color: "#fff",
                  }}
                  >
                  <StyledLink target={"_blank"} href={CONFIG.SCAN_LINK}>
                    Contract address: {truncate(CONFIG.CONTRACT_ADDRESS, 15)}
                  </StyledLink>
                  </s.TextDescription>
                </>
                ) : (
                <>
                  <s.TextTitle2>
                    CLAIM YOUR FREE NFT
                  </s.TextTitle2>
                  <s.TextTitle3>
                    MINTED {data.totalSupply} / {CONFIG.MAX_SUPPLY}
                  </s.TextTitle3>
                  <s.SpacerSmall/>
                </>
                )}         
            <s.SpacerLarge/>
            <s.SpacerLarge/>
            {Number(data.totalSupply) >= CONFIG.MAX_SUPPLY ? (
              <>
                <s.TextTitle
                  style={{ textAlign: "center", color: "var(--accent-text)" }}
                >
                  The sale has ended.
                </s.TextTitle>
                <s.TextDescription
                  style={{ textAlign: "center", color: "var(--accent-text)" }}
                >
                  You can still find {CONFIG.NFT_NAME} on
                </s.TextDescription>
                <s.SpacerSmall />
                <StyledLink target={"_blank"} href={CONFIG.MARKETPLACE_LINK}>
                  {CONFIG.MARKETPLACE}
                </StyledLink>
              </>
            ) : (
              <>
                <s.SpacerSmall />
                {blockchain.account === "" ||
                blockchain.smartContract === null ? (
                  data.getPauseInfo ? (
                  <s.TextTitle>Smart contract is paused...</s.TextTitle>
                  ) : (
                    <s.Container ai={"center"} jc={"center"} style={{marginTop: '40px'}}>
                  <s.TextDescription
                    style={{
                      textAlign: "center",
                      color: "var(--accent-text)",
                    }}
                  >
                    Connect to the {CONFIG.NETWORK.NAME} network
                  </s.TextDescription>
                  <s.SpacerSmall />
                  <StyledButton
                    onClick={(e) => {
                      e.preventDefault();
                      dispatch(connect());
                      getData();
                    }}
                  >
                    CONNECT
                  </StyledButton>
                  {blockchain.errorMsg !== "" ? (
                    <>
                      <s.SpacerSmall />
                      <s.TextDescription
                        style={{
                          textAlign: "center",
                          color: "var(--accent-text)",
                        }}
                      >
                        {blockchain.errorMsg}
                      </s.TextDescription>
                    </>
                  ) : null}
                </s.Container>
                )
                ) : (
                  <>          
                  <hr style={{width: '60%', borderColor: 'rgba(255,255,255,0.4'}} />
                  <s.SpacerMedium />
                  <s.Container ai={"center"} jc={"center"} fd={"row"}>
                    <s.TextDescription2>
                      {feedback}
                    </s.TextDescription2> 
                  </s.Container>   
                  <s.Container ai={"center"} jc={"center"} fd={"row"} style={{marginTop: '20px'}} >
                      <StyledButton2
                        disabled={claimingNft ? 1 : 0}
                        onClick={(e) => {
                          e.preventDefault();
                          mint();
                          getData();
                        }}
                      >
                        {claimingNft ? "BUSY" : `CLAIM`}
                      </StyledButton2>
                    </s.Container>
                  </>
                )}
              </>
            )}
            <s.SpacerMedium />
          </s.Container>
          <s.SpacerLarge />
          <s.Container flex={1} jc={"center"} ai={"center"}>
            <StyledImg
              initial='hidden' animate='visible' variants={fadeRight} transition={{duration: 1}} style={{ scaleX: -1 }} drag={true} dragConstraints={{left: 0, right: 0, top: 0, bottom: 0}}
              alt={"example"}
              src={example1}
            />
          </s.Container>
        </ResponsiveWrapper>
        <s.SpacerMedium />
        <s.Container jc={"center"} ai={"center"} style={{ width: "100%", backgroundColor: 'rgba(0,0,0,0.5)' }}>
          <s.TextDescription
            style={{
              textAlign: "center",
              color: "#fff",
              padding: '10px',
              width: '70%',
              fontSize: '14px'
            }}
          >
            This "Awareness" NFT only conveys the rights to its artwork under creative commons license BY-SA 4.0. It does not convey any digital, virtual or physical rights to the forest. Carbon sequestration rights are only conveyed with the "Mixed Reality" NFT that will be released on a later date.
          </s.TextDescription>
        </s.Container>
      </s.Container>
    </s.Screen>
  );
}

export default App;
